target_small_y = (y - 1) % 3

# Check if the target small field has any empty cells
has_empty = False
start_row = target_small_x * 4
end_row = start_row + 2
start_col = target_small_y * 4
end_col = start_col + 2

for i in range(start_row, end_row + 1):
    for j in range(start_col, end_col + 1):
        if a[i][j] == '.':
            has_empty = True
            break
    if has_empty:
        break

if has_empty:
    # Mark all empty cells in the target small field
    for i in range(start_row, end_row + 1):
        for j in range(start_col, end_col + 1):
            if a[i][j] == '.':
                a[i][j] = '!'
else:
    # Mark all empty cells in any small field
    for i in range(11):
        if i == 3 or i == 7:
            continue
        for j in range(11):
            if j == 3 or j == 7:
                continue
            if a[i][j] == '.':
                a[i][j] = '!'

for row in a:
